import React, { useState, useEffect } from 'react';

export default function HackathonCard({ hackathon, onOpenModal }) {
  // Стан для збереження тексту таймера
  const [timerText, setTimerText] = useState('');
  // Стан для визначення, чи завершився хакатон
  const [isFinished, setIsFinished] = useState(false);

  useEffect(() => {
    // Функція, яка вираховує час
    const calculateTimeLeft = () => {
      const deadline = new Date(hackathon.deadlineIso).getTime();
      const now = Date.now();
      const diffMs = deadline - now;

      if (diffMs <= 0) {
        setTimerText('Хакатон завершено');
        setIsFinished(true);
        return true; // Повертаємо true, щоб зупинити інтервал
      } else {
        const total = Math.floor(diffMs / 1000);
        const days = Math.floor(total / 86400);
        const hours = Math.floor((total % 86400) / 3600);
        const minutes = Math.floor((total % 3600) / 60);
        const seconds = total % 60;

        // Додаємо нуль попереду, якщо число менше 10
        const pad = (val) => (val < 10 ? `0${val}` : val);

        setTimerText(`До завершення: ${days}д. ${hours}год. ${pad(minutes)}хв. ${pad(seconds)}с`);
        setIsFinished(false);
        return false;
      }
    };

    // Викликаємо одразу, щоб не було затримки в 1 секунду при завантаженні
    const finished = calculateTimeLeft();

    // Якщо не завершено - запускаємо інтервал
    let interval;
    if (!finished) {
      interval = setInterval(calculateTimeLeft, 1000);
    }

    // ОЧИЩЕННЯ: коли компонент видаляється з екрану, зупиняємо таймер (дуже важливо в React!)
    return () => clearInterval(interval);
  }, [hackathon.deadlineIso]); // Залежність: якщо зміниться дедлайн, useEffect перезапуститься

  return (
    <article className="feature-card" style={{ display: 'flex', flexDirection: 'column' }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'flex-start', marginBottom: '8px' }}>
        <h3 style={{ margin: 0 }}>{hackathon.title}</h3>
        <span className="status status-progress" style={{ fontSize: '0.75rem', whiteSpace: 'nowrap', marginLeft: '10px', backgroundColor: '#e6f4ea', color: '#137333' }}>
          {hackathon.category}
        </span>
      </div>
      
      {/* Використовуємо ваші старі стилі timer та timer-finished */}
      <p className={isFinished ? "timer timer-finished" : "timer"} style={{ margin: '0 0 12px 0' }}>
        ⏳ {timerText}
      </p>
      
      <p style={{ flexGrow: 1 }}>{hackathon.short}</p>

      <button 
        onClick={() => onOpenModal(hackathon)} 
        className="btn-primary"
        style={{ marginTop: '16px', alignSelf: 'flex-start' }}
        disabled={isFinished} // Блокуємо кнопку, якщо хакатон завершено (як у вашому старому коді)
      >
        Детальніше
      </button>
    </article>
  );
}
